ruleContent.content:
@js:
content=result.match(/_ii_rr\('([^"]+)'\)/)[1];
function _ii_rr(content) {
    content = java.base64Decode(content);
    var arrays = new Array();
    arrays = content.split(',');
    var $chapter = String(java.getString("@@id.chapter@html",false))

    $chapter = $chapter.replace(new RegExp(/\[[\s\S]+?\]/), '');
    var datas = [];
    datas = $chapter.split('<br><br>');
    var $html = '';
    var el = arrays[0];
    var len = datas.length;
    for (var i = 1; i <= len; i++) {
        $html += datas[arrays[i] - el] + '<br/><br/>';
    }
    return $html;
}
_ii_rr(content)+"◎◎"

